#[derive(ClapParser)]
#[command(author, version, about, long_about = None)]
struct Cli {
    #[arg(short = 'c', long, help = "Execute a single command string")]
    command: Option<String>,

    #[arg(short, long, help = "Run in mock mode (no side effects)")]
    mock: bool,

    #[arg(
        short = 'f',
        long,
        help = "Path to config file (.moonshine.knot, aeon.toml)"
    )]
    config: Option<String>,

    #[arg(short, long, help = "Enable verbose logging")]
    verbose: bool,

    #[arg(short, long, help = "UCAN token for authorization")]
    ucan: Option<String>,

    #[arg(
        long,
        help = "Run a single real mesh generation for -c <prompt>, print the result, and exit"
    )]
    oneoff: bool,

    #[arg(
        long,
        default_value_t = 8,
        help = "Number of tokens to generate in --oneoff mode"
    )]
    oneoff_tokens: usize,

    #[arg(help = "Optional .gnot or .gnarly script file to execute")]
    script: Option<PathBuf>,

    #[command(subcommand)]
    subcommand: Option<SubCommand>,
}

#[derive(clap::Subcommand)]
enum SubCommand {
    #[command(about = "Initialize moonshine environment and identity")]
    Init,
    #[command(about = "Diagnose the current environment and configuration")]
    Doctor,
    #[command(about = "Benchmark a command's execution time")]
    Benchmark {
        #[arg(help = "The command string to benchmark")]
        cmd: String,
        #[arg(short, long, default_value_t = 10, help = "Number of iterations")]
        runs: u32,
        #[arg(short, long, default_value_t = 2, help = "Number of warmup runs")]
        warmup: u32,
        #[arg(
            short,
            long,
            help = "Run a performance shootout against other runtimes"
        )]
        shootout: bool,
    },
    #[command(
        about = "Run as a long-lived mesh node: warm the fat-station and stay up for fork/race/fold dispatch (the puppet's persistent mode)"
    )]
    Serve,
}

#[derive(Debug, Serialize, Deserialize, Clone, Default)]
pub struct IdentityConfig {
    pub did: String,
    pub secret: String,
}

#[derive(Debug, Serialize, Deserialize, Clone)]
pub struct AgentConfig {
    #[serde(default = "default_llm_knot")]
    pub llm_knot: String,
    #[serde(default = "default_pneuma_acoustic")]
    pub pneuma_acoustic_knot: String,
    #[serde(default = "default_pneuma_vocoder")]
    pub pneuma_vocoder_knot: String,
}

fn default_llm_knot() -> String {
    // Default to the lightweight Qwen knot when no override is provided.
    // Precedence: explicit env, then cached local models. If no model is cached
    // yet, point at the default cache path so the fat-client startup can stage
    // the download before spawning fat-station.
    if let Ok(p) = std::env::var("MOONSHINE_LLM_KNOT") {
        return p;
    }
    if let Some(home) = home::home_dir() {
        // Honor the Tauri settings UI's active model — it writes `active_model_id`
        // to ~/.moonshine.d/mobile-model.json. The CLI used to ignore this surface
        // entirely (so a UI pick of "Qwen Coder 7B" was silently served as 0.5B).
        if let Ok(txt) = std::fs::read_to_string(home.join(".moonshine.d/mobile-model.json")) {
            if let Ok(v) = serde_json::from_str::<serde_json::Value>(&txt) {
                if let Some(id) = v.get("active_model_id").and_then(|x| x.as_str()) {
                    let id = id.trim().trim_end_matches("-q4");
                    let p = home.join(format!(".edgework/models/{id}.knot"));
                    if p.exists() {
                        return p.to_string_lossy().into_owned();
                    }
                }
            }
        }
        // Fallback precedence: prefer the cached coder-7B, then the 0.5B floor.
        for rel in [
            ".edgework/models/qwen-coder-7b.knot",
            ".edgework/models/qwen2.5-0.5b-instruct.knot",
        ] {
            let p = home.join(rel);
            if p.exists() {
                return p.to_string_lossy().into_owned();
            }
        }
    }
    agent_runtime::default_llm_knot_path()
}

fn default_pneuma_acoustic() -> String {
    "open-source/bitwise/datasets/pneuma_acoustic.knot".to_string()
}

fn default_pneuma_vocoder() -> String {
    "open-source/bitwise/datasets/pneuma_vocoder.knot".to_string()
}

#[derive(Debug, Serialize, Deserialize, Default)]
pub struct Config {
    pub identity: IdentityConfig,
    #[serde(default)]
    pub agent: AgentConfig,
    #[serde(default)]
    pub aliases: std::collections::HashMap<String, String>,
    #[serde(default)]
    pub signed_env_only: bool,
}

impl Default for AgentConfig {
    fn default() -> Self {
        Self {
            llm_knot: default_llm_knot(),
            pneuma_acoustic_knot: default_pneuma_acoustic(),
            pneuma_vocoder_knot: default_pneuma_vocoder(),
        }
    }
}

impl Config {
    fn load(path: Option<String>) -> Result<Self> {
        let paths = if let Some(p) = path {
            vec![PathBuf::from(p)]
        } else {
            let mut search = Vec::new();
            if let Some(home) = home::home_dir() {
                search.push(home.join(".moonshine.knot"));
                search.push(home.join(".moonshine.json"));
                search.push(home.join("aeon.toml"));
            }
            search.push(PathBuf::from(".moonshine.knot"));
            search.push(PathBuf::from(".moonshine.json"));
            search.push(PathBuf::from("aeon.toml"));
            search
        };

        for p in paths {
            if p.exists() {
                let content = fs::read_to_string(&p)?;
                let extension = p.extension().and_then(|s| s.to_str());

                if extension == Some("toml")
                    || p.file_name() == Some(std::ffi::OsStr::new("aeon.toml"))
                {
                    return toml::from_str(&content)
                        .map_err(|e| anyhow!("Failed to parse TOML {}: {}", p.display(), e));
                } else {
                    return serde_json::from_str(&content)
                        .map_err(|e| anyhow!("Failed to parse JSON {}: {}", p.display(), e));
                }
            }
        }

        Ok(Config {
            identity: IdentityConfig {
                did: "did:key:z6MkqMoonshineDefault".to_string(),
                secret: "default-secret-do-not-use-in-prod".to_string(),
            },
            agent: AgentConfig::default(),
            aliases: std::collections::HashMap::new(),
            signed_env_only: false,
        })
    }
}

const REGISTERED_COMMAND_ALIASES: &[(&str, &str)] = &[
    ("ping", "wall ping"),
    ("traceroute", "wall traceroute"),
    ("tracert", "wall tracert"),
    ("wireshark", "wall wireshark"),
    ("dig", "wall dig"),
    ("nslookup", "wall nslookup"),
    ("open", "wall open"),
    ("pbcopy", "wall clipboard-write"),
    ("pbpaste", "wall clipboard-read"),
    ("ip", "wall ip"),
    ("ss", "wall sockets"),
    ("ipconfig", "wall ipconfig"),
    ("sw_vers", "moonbeam platform"),
    ("systemctl", "moonbeam services"),
    ("journalctl", "moonbeam logs"),
    ("tasklist", "moonbeam ps"),
    ("dir", "rip ls"),
    ("where", "rip which"),
];

fn register_builtin_aliases(config: &mut Config) {
    for (alias, command) in REGISTERED_COMMAND_ALIASES {
        config
            .aliases
            .entry((*alias).to_string())
            .or_insert_with(|| (*command).to_string());
    }
}

fn get_gnosis_time() -> String {
    let now_ms = Utc::now().timestamp_millis() as f64;
    let picolorenzo_ms = std::f64::consts::PI * 86400.0 * 1000.0;
    let plo = now_ms / picolorenzo_ms;

    // Gnostic Decomposition
    let pleroma = 55.0;
    let aeon = 2.0 * pleroma; // 110
    let kenoma = 10.0;
    let sophia = 9.0;

    let mut remaining = plo;

    let aeons = (remaining / aeon).floor();
    remaining -= aeons * aeon;

    let pleromas = (remaining / pleroma).floor();
    remaining -= pleromas * pleroma;

    let kenomas = (remaining / kenoma).floor();
    remaining -= kenomas * kenoma;

    let sophias = (remaining / sophia).floor();
    remaining -= sophias * sophia;

    let barbelos = remaining.floor();

    let mut parts = Vec::new();
    if aeons > 0.0 {
        parts.push(format!("{}a", aeons));
    }
    if pleromas > 0.0 {
        parts.push(format!("{}p", pleromas));
    }
    if kenomas > 0.0 {
        parts.push(format!("{}k", kenomas));
    }
    if sophias > 0.0 {
        parts.push(format!("{}s", sophias));
    }
    if barbelos > 0.0 {
        parts.push(format!("{}b", barbelos));
    }

    if parts.is_empty() {
        "0b".to_string()
    } else {
        parts.join(" ")
    }
}

#[derive(Helper, Hinter, Highlighter, Validator, Completer)]
struct MoonshineHelper {
    #[rustyline(Completer)]
    completer: FilenameCompleter,
}

/// Strip one layer of matching surrounding quotes from a value.
fn unquote(s: &str) -> String {
    let b = s.as_bytes();
    if b.len() >= 2 && (b[0] == b'"' || b[0] == b'\'') && b[b.len() - 1] == b[0] {
        s[1..s.len() - 1].to_string()
    } else {
        s.to_string()
    }
}

/// Expand `$VAR` / `${VAR}` against the current environment so a harvested
/// `export PATH="$HOME/bin:$PATH"` becomes a real path. Unknown vars expand to
/// empty, matching shell behavior.
fn expand_env_vars(s: &str) -> String {
    let mut out = String::with_capacity(s.len());
    let mut chars = s.chars().peekable();
    while let Some(c) = chars.next() {
        if c != '$' {
            out.push(c);
            continue;
        }
        let mut name = String::new();
        if chars.peek() == Some(&'{') {
            chars.next();
            while let Some(&nc) = chars.peek() {
                if nc == '}' {
                    chars.next();
                    break;
                }
                name.push(nc);
                chars.next();
            }
        } else {
            while let Some(&nc) = chars.peek() {
                if nc.is_ascii_alphanumeric() || nc == '_' {
                    name.push(nc);
                    chars.next();
                } else {
                    break;
                }
            }
        }
        if name.is_empty() {
            out.push('$');
        } else {
            out.push_str(&std::env::var(&name).unwrap_or_default());
        }
    }
    out
}

fn is_env_name(k: &str) -> bool {
    !k.is_empty()
        && k.chars().all(|c| c.is_ascii_alphanumeric() || c == '_')
        && !k.chars().next().unwrap().is_ascii_digit()
}

/// A portable rc declaration moonshine understands. Foreign zsh/bash lines
/// (functions, `setopt`, completion init) parse to `None` and are ignored.
enum RcDecl {
    Alias(String, String),
    Export(String, String),
}

/// Classify one rc line. Shared by the harvester and `doctor` so what gets
/// reported is exactly what gets applied (export values are `$VAR`-expanded).
fn parse_rc_line(raw: &str) -> Option<RcDecl> {
    let line = raw.trim();
    if line.is_empty() || line.starts_with('#') {
        return None;
    }
    if let Some(rest) = line.strip_prefix("alias ") {
        let (name, val) = rest.split_once('=')?;
        let name = name.trim();
        // Skip flag forms (`alias -g …`) and anything with whitespace.
        if name.is_empty() || name.starts_with('-') || name.chars().any(char::is_whitespace) {
            return None;
        }
        return Some(RcDecl::Alias(name.to_string(), unquote(val.trim())));
    }
    if let Some(rest) = line.strip_prefix("export ") {
        let (key, val) = rest.split_once('=')?;
        let key = key.trim();
        if !is_env_name(key) {
            return None;
        }
        return Some(RcDecl::Export(
            key.to_string(),
            expand_env_vars(&unquote(val.trim())),
        ));
    }
    None
}

/// Count the aliases/exports a given rc would contribute (for `doctor`), without
/// applying anything.
fn count_rc_decls(path: &std::path::Path) -> (usize, usize) {
    let Ok(content) = std::fs::read_to_string(path) else {
        return (0, 0);
    };
    let (mut a, mut e) = (0usize, 0usize);
    for raw in content.lines() {
        match parse_rc_line(raw) {
            Some(RcDecl::Alias(..)) => a += 1,
            Some(RcDecl::Export(..)) => e += 1,
            None => {}
        }
    }
    (a, e)
}

/// Make moonshine easy to adopt: pull the user's existing aliases and PATH/env
/// exports from their shell rc so nothing has to be redefined by hand. Prefers a
/// native `~/.moonshinerc`; otherwise harvests only the *portable* declarations
/// (`alias …`, `export …`) from `~/.zshrc` then `~/.bashrc`, ignoring the
/// zsh/bash-specific lines (functions, `setopt`, completion/oh-my-zsh init) that
/// moonshine's parser can't run. Existing `.moonshine.knot` aliases always win.
/// `MOONSHINE_NO_RC=1` opts out.
fn bootstrap_user_shell(config: &mut Config) {
    if std::env::var("MOONSHINE_NO_RC")
        .map(|v| v == "1" || v.eq_ignore_ascii_case("true"))
        .unwrap_or(false)
    {
        return;
    }
    let Some(home) = home::home_dir() else {
        return;
    };
    let Some(rc) = [".moonshinerc", ".zshrc", ".bashrc"]
        .iter()
        .map(|n| home.join(n))
        .find(|p| p.exists())
    else {
        return;
    };
    let Ok(content) = std::fs::read_to_string(&rc) else {
        return;
    };

    let (mut aliases, mut exports) = (0usize, 0usize);
    for raw in content.lines() {
        match parse_rc_line(raw) {
            // Existing .moonshine.knot aliases always win — don't override.
            Some(RcDecl::Alias(name, val)) => {
                if let std::collections::hash_map::Entry::Vacant(entry) =
                    config.aliases.entry(name)
                {
                    entry.insert(val);
                    aliases += 1;
                }
            }
            Some(RcDecl::Export(key, val)) => {
                std::env::set_var(&key, val);
                exports += 1;
            }
            None => {}
        }
    }
    if aliases + exports > 0 {
        eprintln!(
            "\x1b[90m[moonshine] sourced ~/{}: {} aliases, {} exports\x1b[0m",
            rc.file_name()
                .map(|n| n.to_string_lossy().into_owned())
                .unwrap_or_default(),
            aliases,
            exports
        );
    }
}

#[tokio::main]
async fn main() -> Result<()> {
    let cli = Cli::parse();
    let mut config = Config::load(cli.config.clone())?;
    register_builtin_aliases(&mut config);

    if cli.verbose {
        std::env::set_var("MOONSHINE_VERBOSE", "1");
        eprintln!("[moonshine] verbose logging enabled");
    }

    let mut parser = Parser::new();
    let language = tree_sitter_bash::LANGUAGE.into();
    parser.set_language(&language)?;

    let mock_history = Arc::new(Mutex::new(Vec::new()));

    if let Some(sub) = cli.subcommand {
        match sub {
            SubCommand::Init => {
                let config_path = PathBuf::from(".moonshine.knot");
                if config_path.exists() {
                    println!("Moonshine is already initialized (.moonshine.knot exists).");
                } else {
                    let did = format!("did:key:z6Mkq{}", hex::encode(rand::random::<[u8; 16]>()));
                    let secret = hex::encode(rand::random::<[u8; 32]>());
                    let config = Config {
                        identity: IdentityConfig { did, secret },
                        agent: AgentConfig::default(),
                        aliases: std::collections::HashMap::from([
                            ("ll".to_string(), "ls -la".to_string()),
                            ("gs".to_string(), "git status".to_string()),
                        ]),
                        signed_env_only: false,
                    };
                    let content = serde_json::to_string_pretty(&config)?;
                    fs::write(&config_path, content)?;
                    println!("Initialized moonshine at {}", config_path.display());
                    println!("DID: {}", config.identity.did);
                }
                return Ok(());
            }
            SubCommand::Doctor => {
                println!("☾☽ Moonshine Doctor — Diagnosing Environment");
                println!("-------------------------------------------");
                let config_res = Config::load(cli.config.clone());
                match config_res {
                    Ok(cfg) => {
                        println!("[✓] Configuration loaded");
                        println!("    Identity: {}", cfg.identity.did);
                        println!("    Aliases: {} defined", cfg.aliases.len());
                    }
                    Err(e) => println!("[✗] Configuration error: {}", e),
                }

                let cwd = std::env::current_dir()?;
                println!("[✓] Working Directory: {}", cwd.display());

                if cwd.join(".env").exists() {
                    println!("[✓] Found .env file");
                }
                if cwd.join(".env.knot").exists() {
                    println!("[✓] Found .env.knot file");
                }
                if cwd.join(".env.local").exists() {
                    println!("[✓] Found .env.local file (auto-loaded, overrides .env)");
                }

                // Which shell rc moonshine harvests aliases + exports from.
                if let Some(home) = home::home_dir() {
                    match [".moonshinerc", ".zshrc", ".bashrc"]
                        .iter()
                        .map(|n| home.join(n))
                        .find(|p| p.exists())
                    {
                        Some(rc) => {
                            let (a, e) = count_rc_decls(&rc);
                            println!(
                                "[✓] Shell rc: ~/{} ({} aliases, {} exports)",
                                rc.file_name()
                                    .map(|n| n.to_string_lossy().into_owned())
                                    .unwrap_or_default(),
                                a,
                                e
                            );
                        }
                        None => {
                            println!("[!] No ~/.moonshinerc / ~/.zshrc / ~/.bashrc found to source")
                        }
                    }
                }

                match which::which("moonshine") {
                    Ok(p) => println!("[✓] Moonshine binary in PATH: {}", p.display()),
                    Err(_) => println!("[!] Moonshine not found in PATH"),
                }

                println!("-------------------------------------------");
                println!("Diagnosis complete.");
                return Ok(());
            }
            SubCommand::Serve => {
                let config = Config::load(cli.config.clone())?;
                agent_runtime::run_serve(&config).await?;
                return Ok(());
            }
            SubCommand::Benchmark {
                cmd,
                runs,
                warmup,
                shootout,
            } => {
                if shootout {
                    run_shootout(runs, warmup).await?;
                    return Ok(());
                }
                println!("☾☽ Moonshine Benchmark — Measuring Execution Latency");
                println!("Command: {}", cmd);
                println!("Warmup: {} runs, Measurement: {} runs", warmup, runs);
                println!("--------------------------------------------------");

                let mut parser = Parser::new();
                let language = tree_sitter_bash::LANGUAGE.into();
                parser.set_language(&language)?;

                let backend = NativeBackend::new(
                    config.identity.did.clone(),
                    config.identity.secret.clone(),
                    config.signed_env_only,
                    cli.verbose,
                );

                // Warmup
                for i in 0..warmup {
                    print!("\rWarmup {}/{}...", i + 1, warmup);
                    let _ = std::io::Write::flush(&mut std::io::stdout());
                    let b: Box<dyn executor::Backend> = Box::new(NativeBackend {
                        state: backend.state.clone(),
                        amplituhedron: backend.amplituhedron.clone(),
                    });
                    handle_command(&cmd, &mut parser, b, cli.ucan.clone(), &config).await?;
                }
                println!("\rWarmup complete.       ");

                let mut times = Vec::new();
                for i in 0..runs {
                    print!("\rMeasuring {}/{}...", i + 1, runs);
                    let _ = std::io::Write::flush(&mut std::io::stdout());
                    let start = std::time::Instant::now();
                    let b: Box<dyn executor::Backend> = Box::new(NativeBackend {
                        state: backend.state.clone(),
                        amplituhedron: backend.amplituhedron.clone(),
                    });
                    handle_command(&cmd, &mut parser, b, cli.ucan.clone(), &config).await?;
                    times.push(start.elapsed());
                }
                println!("\rMeasurement complete.  ");

                let durations: Vec<f64> = times.iter().map(|d| d.as_secs_f64() * 1000.0).collect();
                let min = durations.iter().fold(f64::INFINITY, |a, &b| a.min(b));
                let max = durations.iter().fold(f64::NEG_INFINITY, |a, &b| a.max(b));
                let sum: f64 = durations.iter().sum();
                let mean = sum / runs as f64;

                let variance: f64 = durations.iter().map(|&d| (d - mean).powi(2)).sum::<f64>()
                    / (runs as f64).max(1.0);
                let stddev = variance.sqrt();

                println!("--------------------------------------------------");
                println!("Results (ms):");
                println!("  Mean:   {:.3} ms", mean);
                println!("  Min:    {:.3} ms", min);
                println!("  Max:    {:.3} ms", max);
                println!("  StdDev: {:.3} ms", stddev);
                println!("--------------------------------------------------");

                return Ok(());
            }
        }
    }

    if cli.oneoff {
        let prompt = cli.command.clone().ok_or_else(|| {
            anyhow!("--oneoff requires a prompt via -c <prompt> (e.g. moonshine --oneoff -c \"The capital of France is\")")
        })?;
        agent_runtime::run_oneoff(&config, &prompt, cli.oneoff_tokens).await?;
        return Ok(());
    }

    if let Some(cmd_str) = cli.command {
        let backend: Box<dyn executor::Backend> = if cli.mock {
            Box::new(executor::MockBackend {
                history: mock_history.clone(),
            })
        } else {
            Box::new(NativeBackend::new(
                config.identity.did.clone(),
                config.identity.secret.clone(),
                config.signed_env_only,
                cli.verbose,
            ))
        };
        let cmd_str = normalize_single_command(&cmd_str)?;
        if cmd_str.is_empty() {
            return Ok(());
        }
        handle_command(&cmd_str, &mut parser, backend, cli.ucan, &config).await?;
        return Ok(());
    }

    if let Some(script_path) = cli.script {
        let backend: Box<dyn executor::Backend> = if cli.mock {
            Box::new(executor::MockBackend {
                history: mock_history.clone(),
            })
        } else {
            Box::new(NativeBackend::new(
                config.identity.did.clone(),
                config.identity.secret.clone(),
                config.signed_env_only,
                cli.verbose,
            ))
        };

        if script_path.extension().and_then(|s| s.to_str()) == Some("gnot") {
            let source = fs::read_to_string(&script_path)?;
            let cfg = gnot_compiler::compile_gnot_to_cfg(&source, script_path.to_str().unwrap())?;
            let executor = GgExecutor::new(cfg, backend, cli.ucan);
            executor.execute().await?;
        } else if script_path.extension().and_then(|s| s.to_str()) == Some("gnarly") {
            let source = fs::read_to_string(&script_path)?;
            let cfg = gnot_compiler::compile_gnarly_to_cfg(&source, script_path.to_str().unwrap())?;
            let executor = GgExecutor::new(cfg, backend, cli.ucan);
            executor.execute().await?;
        } else if needs_runner(&script_path) {
            // The sovereign runner: `.iso`/`.img` boots in a microVM (live
            // console); a polyglot source runs as FOIL on the vCPU — certified.
            dispatch_run(&script_path.to_string_lossy()).await?;
        } else {
            let source = fs::read_to_string(&script_path)?;
            handle_command(&source, &mut parser, backend, cli.ucan, &config).await?;
        }
        return Ok(());
    }

    let mut rl = Editor::new()?;
    rl.set_helper(Some(MoonshineHelper {
        completer: FilenameCompleter::new(),
    }));
    bind_facet_hotkeys(&mut rl);
    let mut facets = FacetDeck::new(std::env::current_dir()?);

    // Easy adoption: pull the user's existing aliases + PATH/exports from their
    // shell rc (native ~/.moonshinerc, else ~/.zshrc / ~/.bashrc) so the shell
    // feels like home on first run. Interactive sessions only.
    bootstrap_user_shell(&mut config);

    println!("moonshine — Monster On Shell In Engine (The FRF Shell)");
    println!("Identity: {}", config.identity.did);
    println!("Type 'exit' or Ctrl-D to quit.");

    loop {
        let gtime = get_gnosis_time();
        let prompt = format!(
            "[{} f{}/{} {}] ☾☽ ",
            gtime,
            facets.active,
            facets.open_count,
            facets.active().label
        );
        let readline = rl.readline(&prompt);

        match readline {
            Ok(line) => {
                if line.trim() == "exit" {
                    break;
                }
                if line.trim().is_empty() {
                    continue;
                }
                rl.add_history_entry(line.as_str())?;

                if line.trim() == "ucan" {
                    let token =
                        generate_session_token(&config.identity.did, &config.identity.secret)?;
                    println!("Session UCAN: {}", token);
                    continue;
                }

                if let Some(action) = decode_hotkey_line(&line) {
                    apply_facet_action(&mut facets, action)?;
                    continue;
                }

                let line_to_run = if let Some(command) = line.trim().strip_prefix('!') {
                    let command = command.trim();
                    if command.is_empty() {
                        facets.fork_active(None);
                        continue;
                    }
                    facets.fork_active(Some(command));
                    command.to_string()
                } else if handle_facet_command(line.trim(), &mut facets)? {
                    continue;
                } else {
                    line.clone()
                };

                let backend: Box<dyn executor::Backend> = if cli.mock {
                    Box::new(executor::MockBackend {
                        history: mock_history.clone(),
                    })
                } else {
                    Box::new(NativeBackend::new(
                        config.identity.did.clone(),
                        config.identity.secret.clone(),
                        config.signed_env_only,
                        cli.verbose,
                    ))
                };

                let ucan = cli
                    .ucan
                    .clone()
                    .or_else(|| std::env::var("MOONSHINE_UCAN").ok());

                if let Err(e) =
                    handle_command(&line_to_run, &mut parser, backend, ucan, &config).await
                {
                    eprintln!("Error: {}", e);
                } else {
                    facets.note_command(&line_to_run);
                    facets.sync_active_cwd_from_process();
                }
            }
            Err(ReadlineError::Interrupted) => {
                println!("CTRL-C");
                continue;
            }
            Err(ReadlineError::Eof) => {
                println!("CTRL-D");
                break;
            }
            Err(err) => {
                println!("Error: {:?}", err);
                break;
            }
        }
    }
    Ok(())
}

fn normalize_single_command(line: &str) -> Result<String> {
    let trimmed = line.trim();
    if let Some(command) = trimmed.strip_prefix('!') {
        return Ok(command.trim().to_string());
    }
    if trimmed.starts_with("facet") {
        let mut facets = FacetDeck::new(std::env::current_dir()?);
        handle_facet_command(trimmed, &mut facets)?;
        return Ok(String::new());
    }
    Ok(line.to_string())
}

fn bind_facet_hotkeys(rl: &mut Editor<MoonshineHelper, rustyline::history::DefaultHistory>) {
    rl.bind_sequence(
        KeyEvent(KeyCode::Char('T'), Modifiers::CTRL),
        EventHandler::from(Cmd::Insert(1, "facet fork\n".to_string())),
    );
    rl.bind_sequence(
        KeyEvent(KeyCode::Char('W'), Modifiers::CTRL),
        EventHandler::from(Cmd::Insert(1, "facet close\n".to_string())),
    );
    rl.bind_sequence(
        KeyEvent(KeyCode::Tab, Modifiers::CTRL),
        EventHandler::from(Cmd::Insert(1, "facet next\n".to_string())),
    );
    rl.bind_sequence(
        KeyEvent(KeyCode::BackTab, Modifiers::SHIFT),
        EventHandler::from(Cmd::Insert(1, "facet prev\n".to_string())),
    );
}

#[derive(Debug, Clone, Copy)]
enum FacetAction {
    Fork,
    Close,
    CloseOthers,
    CloseChildren,
    Next,
    Prev,
    List,
}

fn decode_hotkey_line(line: &str) -> Option<FacetAction> {
    match line.trim() {
        "facet fork" => Some(FacetAction::Fork),
        "facet close" => Some(FacetAction::Close),
        "facet next" => Some(FacetAction::Next),
        "facet prev" => Some(FacetAction::Prev),
        _ => None,
    }
}

fn handle_facet_command(line: &str, facets: &mut FacetDeck) -> Result<bool> {
    let Some(rest) = line.strip_prefix("facet") else {
        return Ok(false);
    };
    let action = match rest.trim() {
        "" | "list" | "ls" => FacetAction::List,
        "fork" | "new" => FacetAction::Fork,
        "close" | "close active" => FacetAction::Close,
        "next" => FacetAction::Next,
        "prev" | "previous" => FacetAction::Prev,
        "close others" | "close-others" | "only" => FacetAction::CloseOthers,
        "close children" | "close-children" => FacetAction::CloseChildren,
        other => return Err(anyhow!("unknown facet command: facet {}", other)),
    };
    apply_facet_action(facets, action)?;
    Ok(true)
}

fn apply_facet_action(facets: &mut FacetDeck, action: FacetAction) -> Result<()> {
    match action {
        FacetAction::Fork => {
            let id = facets.fork_active(None);
            println!("facet {} forked", id);
        }
        FacetAction::Close => {
            let id = facets.close_active();
            println!("facet {} active", id);
        }
        FacetAction::CloseOthers => {
            facets.close_all_others();
            println!("facet {} kept", facets.active);
        }
        FacetAction::CloseChildren => {
            facets.close_children();
            println!("facet {} children closed", facets.active);
        }
        FacetAction::Next => {
            let id = facets.switch_result(FacetMove::Next);
            println!("facet {} active", id);
        }
        FacetAction::Prev => {
            let id = facets.switch_result(FacetMove::Prev);
            println!("facet {} active", id);
        }
        FacetAction::List => {
            println!("{}", serde_json::to_string(facets)?);
        }
    }
    Ok(())
}

fn should_handoff_to_fat_client(err: &anyhow::Error) -> bool {
    let msg = err.to_string();
    msg.contains("Failed to parse command")
        || msg.contains("Failed to spawn")
        || msg.contains("no Moonshine standard-pack admission row")
        || msg.contains("not found")
}

fn looks_like_chat_prompt(line: &str, first_word: &str) -> bool {
    if line.trim_end().ends_with('?') {
        return true;
    }
    matches!(
        first_word.to_ascii_lowercase().as_str(),
        "what"
            | "why"
            | "how"
            | "who"
            | "where"
            | "when"
            | "which"
            | "explain"
            | "tell"
            | "can"
            | "could"
            | "would"
            | "should"
    )
}

/// Whether `moonshine <file>` should route the file through the sovereign runner:
/// a disk image (`.iso`/`.img`) or a polyglot FOIL source.
fn needs_runner(path: &std::path::Path) -> bool {
    matches!(
        path.extension().and_then(|s| s.to_str()),
        Some(
            "iso" | "img" | "ts" | "tsx" | "js" | "py" | "rs" | "go" | "java" | "kt" | "lean"
        )
    )
}

/// Classify `target` and run it on the right substrate via `vcpu::runner`. A
/// `.iso`/`.img` boots a live interactive microVM; everything else is admitted +
/// dispatched (FOIL on the vCPU, native binary, or OCI image) and the report is
/// printed. Blocking runner calls run on a blocking thread.
async fn dispatch_run(target: &str) -> Result<()> {
    use vcpu::runner::{classify, RunClass};
    // `run <iso> -- <command>` boots the iso and runs the command INSIDE the
    // guest, returning braid-certified output (a verified job in a throwaway VM).
    if let Some((tgt, cmd)) = target.split_once(" -- ") {
        let tgt = tgt.trim();
        if matches!(classify(tgt), RunClass::OpaqueIso { .. }) {
            let (iso, cmd) = (tgt.to_string(), cmd.trim().to_string());
            let report =
                tokio::task::spawn_blocking(move || vcpu::runner::exec_in_iso(&iso, &cmd, None))
                    .await?
                    .map_err(|e| anyhow!("exec-in-iso failed: {e}"))?;
            println!("[cert {}] {}", report.cert_hash, report.evidence);
            if !report.output.is_empty() {
                println!("--- guest output ---\n{}", report.output);
            }
            return Ok(());
        }
    }
    if matches!(classify(target), RunClass::OpaqueIso { .. }) {
        let iso = target.to_string();
        tokio::task::spawn_blocking(move || vcpu::runner::boot_iso_interactive(&iso, None))
            .await?
            .map_err(|e| anyhow!("boot failed: {e}"))?;
        return Ok(());
    }
    let t = target.to_string();
    let report = tokio::task::spawn_blocking(move || vcpu::runner::run(&t, "{}"))
        .await?
        .map_err(|e| anyhow!("run failed: {e}"))?;
    print_run_report(&report);
    Ok(())
}

/// `vm checkout <target>` — boot an ISO with a PERSISTENT overlay that syncs to
/// edgework, so the guest's `/dev/vdb` data follows you to any device. Pull the
/// prior overlay, boot with it attached, then push it back on poweroff
/// (resume-anywhere — the streaming-disk model, wired to a real boot).
async fn vm_checkout(target: &str) -> Result<()> {
    use vcpu::runner::{classify, RunClass};
    if !matches!(classify(target), RunClass::OpaqueIso { .. }) {
        return Err(anyhow!("vm checkout needs an ISO / aeon://iso/<id> target"));
    }
    let did = std::env::var("AEON_DID").unwrap_or_else(|_| "did:aeon:local".to_string());
    let did_safe = sanitize_did(&did);
    let id = checkout_id(target);
    let base = std::env::var("EDGEWORK_R2")
        .unwrap_or_else(|_| "https://edgework.ai/api/v1/r2/edge-vfs".to_string());
    let url = format!("{base}/users/{did_safe}/checkouts/{id}/overlay.img");
    let local = checkout_overlay_path(&id)?;

    let resumed = pull_overlay(&url, &local);
    println!(
        "[checkout] {} for '{id}' ({did}) → {}",
        if resumed { "resumed remote overlay" } else { "fresh overlay" },
        local.display()
    );

    let iso = target.to_string();
    let lp = local.clone();
    tokio::task::spawn_blocking(move || vcpu::runner::boot_iso_interactive(&iso, Some(&lp)))
        .await?
        .map_err(|e| anyhow!("boot failed: {e}"))?;

    match push_overlay(&url, &local) {
        Ok(()) => println!("[checkout] overlay synced → edgework (resume anywhere)"),
        Err(e) => eprintln!(
            "[checkout] overlay kept locally at {} (remote sync skipped: {e})",
            local.display()
        ),
    }
    Ok(())
}

/// Sanitize a DID for an R2 key path — must match disk-auth's `userPrefix`
/// (keeps [A-Za-z0-9._:-], so `did:aeon:x` stays intact for the scope check).
fn sanitize_did(did: &str) -> String {
    did.chars()
        .map(|c| if c.is_ascii_alphanumeric() || matches!(c, '.' | '_' | ':' | '-') { c } else { '_' })
        .collect()
}

/// A stable per-image checkout id: `aeon://iso/<id>` → `<id>`, else the basename.
fn checkout_id(target: &str) -> String {
    let raw = target.strip_prefix("aeon://iso/").map_or_else(
        || target.rsplit('/').next().unwrap_or("vm").split('.').next().unwrap_or("vm"),
        |s| s.trim_matches('/'),
    );
    raw.chars()
        .map(|c| if c.is_ascii_alphanumeric() || matches!(c, '-' | '_') { c } else { '-' })
        .collect()
}

fn checkout_overlay_path(id: &str) -> Result<std::path::PathBuf> {
    let cache = std::env::var_os("XDG_CACHE_HOME")
        .map(std::path::PathBuf::from)
        .or_else(|| std::env::var_os("HOME").map(|h| std::path::PathBuf::from(h).join(".cache")))
        .unwrap_or_else(std::env::temp_dir);
    let dir = cache.join("moonshine").join("checkouts").join(id);
    std::fs::create_dir_all(&dir).map_err(|e| anyhow!("mkdir checkout dir: {e}"))?;
    Ok(dir.join("overlay.img"))
}

/// Pull a prior overlay from edgework to `dest`. Returns true if one was present.
fn pull_overlay(url: &str, dest: &std::path::Path) -> bool {
    let status = std::process::Command::new("curl")
        .args(["-fsL", "-o"])
        .arg(dest)
        .arg(url)
        .status();
    matches!(status, Ok(s) if s.success())
        && std::fs::metadata(dest).map(|m| m.len() > 0).unwrap_or(false)
}

/// Push the overlay back to edgework (gated write — scoped to users/<did>/* by the
/// multi-tenant gate). Auth from `AEON_R2_TOKEN` (a user UCAN or the admin token).
fn push_overlay(url: &str, src: &std::path::Path) -> Result<()> {
    if std::fs::metadata(src).map(|m| m.len() == 0).unwrap_or(true) {
        return Err(anyhow!("no overlay to push"));
    }
    let token = std::env::var("AEON_R2_TOKEN").unwrap_or_default();
    let mut cmd = std::process::Command::new("curl");
    cmd.args(["-fsS", "-X", "PUT", "--data-binary"])
        .arg(format!("@{}", src.display()));
    if !token.is_empty() {
        cmd.arg("-H").arg(format!("Authorization: Bearer {token}"));
    }
    cmd.arg(url);
    let out = cmd.output().map_err(|e| anyhow!("curl put: {e}"))?;
    if !out.status.success() {
        return Err(anyhow!(
            "HTTP PUT failed: {}",
            String::from_utf8_lossy(&out.stderr).trim()
        ));
    }
    Ok(())
}

