fn generate_session_token(did: &str, secret: &str) -> Result<String> {
    let payload = serde_json::json!({
        "iss": did,
        "aud": "moonshine",
        "sub": "user",
        "exp": Utc::now().timestamp() + 3600,
        "cap": ["aeon/process"]
    });

    let payload_json = serde_json::to_string(&payload)?;
    let payload_b64 = general_purpose::URL_SAFE_NO_PAD.encode(payload_json);

    let mut mac = HmacSha256::new_from_slice(secret.as_bytes())
        .map_err(|e| anyhow!("Invalid key size: {}", e))?;
    mac.update(payload_b64.as_bytes());
    let signature = mac.finalize().into_bytes();
    let signature_b64 = general_purpose::URL_SAFE_NO_PAD.encode(signature);

    Ok(format!("{}.{}", payload_b64, signature_b64))
}
async fn run_shootout(runs: u32, warmup: u32) -> Result<()> {
    println!("☾☽ Moonshine Runtime Shootout — Performance Comparison");
    println!("Warmup: {} runs, Measurement: {} runs", warmup, runs);
    println!("--------------------------------------------------");

    let mut parser = Parser::new();
    let language = tree_sitter_bash::LANGUAGE.into();
    parser.set_language(&language)?;

    let config = Config::load(None).unwrap_or_default();
    let ucan = generate_session_token(&config.identity.did, &config.identity.secret).ok();

    let runtimes = vec![
        ("moonshine (builtin)", "echo hi", true),
        ("sh -c (builtin)", "echo hi", false),
        ("bash -c (builtin)", "echo hi", false),
        ("zsh -c (builtin)", "echo hi", false),
        ("moonshine (external)", "ls", true),
        ("sh -c (external)", "ls", false),
        ("bash -c (external)", "ls", false),
        ("moonshine (fib 20)", "fib 20", true),
        (
            "node -e (fib 20)",
            "function f(n){if(n<=1)return n;return f(n-1)+f(n-2)}console.log(f(20))",
            false,
        ),
        (
            "bun -e (fib 20)",
            "function f(n){if(n<=1)return n;return f(n-1)+f(n-2)}console.log(f(20))",
            false,
        ),
        ("node -e", "console.log('hi')", false),
        ("bun -e", "console.log('hi')", false),
    ];

    println!(
        "{:<25} | {:<10} | {:<10}",
        "Runtime", "Mean (ms)", "Min (ms)"
    );
    println!("{}", "-".repeat(50));

    for (name, command, is_moonshine) in runtimes {
        let mut times = Vec::new();

        // Warmup
        for _ in 0..warmup {
            if is_moonshine {
                let backend = Box::new(NativeBackend::new(
                    config.identity.did.clone(),
                    config.identity.secret.clone(),
                    config.signed_env_only,
                    false,
                ));
                let _ = handle_command(command, &mut parser, backend, ucan.clone(), &config).await;
            } else {
                let _ = std::process::Command::new(name.split_whitespace().next().unwrap())
                    .arg("-c")
                    .arg(command)
                    .stdout(std::process::Stdio::null())
                    .stderr(std::process::Stdio::null())
                    .status();
            }
        }

        // Measure
        for _ in 0..runs {
            let start = std::time::Instant::now();
            if is_moonshine {
                let backend = Box::new(NativeBackend::new(
                    config.identity.did.clone(),
                    config.identity.secret.clone(),
                    config.signed_env_only,
                    false,
                ));
                let _ = handle_command(command, &mut parser, backend, ucan.clone(), &config).await;
            } else {
                let mut cmd_parts = name.split_whitespace();
                let program = cmd_parts.next().unwrap();
                let arg_flag = if program == "node" || program == "bun" {
                    "-e"
                } else {
                    "-c"
                };

                let _ = std::process::Command::new(program)
                    .arg(arg_flag)
                    .arg(command)
                    .stdout(std::process::Stdio::null())
                    .stderr(std::process::Stdio::null())
                    .status();
            }
            times.push(start.elapsed());
        }

        let durations: Vec<f64> = times.iter().map(|d| d.as_secs_f64() * 1000.0).collect();
        let sum: f64 = durations.iter().sum();
        let mean = sum / runs as f64;
        let min = durations.iter().fold(f64::INFINITY, |a, &b| a.min(b));

        println!("{:<25} | {:<10.3} | {:<10.3}", name, mean, min);
    }

    println!("--------------------------------------------------");
    Ok(())
}

#[cfg(test)]
mod rc_tests {
    use super::*;

    #[test]
    fn unquote_strips_matching_quotes() {
        assert_eq!(unquote("'ls -la'"), "ls -la");
        assert_eq!(unquote("\"git status\""), "git status");
        assert_eq!(unquote("bare"), "bare");
        assert_eq!(unquote("'mismatched\""), "'mismatched\"");
    }

    #[test]
    fn expand_env_vars_handles_braces_and_bare() {
        std::env::set_var("RC_TEST_HOME", "/home/x");
        assert_eq!(expand_env_vars("$RC_TEST_HOME/bin"), "/home/x/bin");
        assert_eq!(expand_env_vars("${RC_TEST_HOME}/y"), "/home/x/y");
        assert_eq!(expand_env_vars("no-vars"), "no-vars");
        // Unknown var -> empty, like a shell.
        assert_eq!(expand_env_vars("$RC_DEFINITELY_UNSET/z"), "/z");
    }

    #[test]
    fn is_env_name_rejects_junk() {
        assert!(is_env_name("PATH"));
        assert!(is_env_name("MY_VAR_2"));
        assert!(!is_env_name("2BAD"));
        assert!(!is_env_name("has-dash"));
        assert!(!is_env_name(""));
    }

    #[test]
    fn parse_rc_line_picks_alias_and_export_skips_foreign() {
        std::env::set_var("RC_PARSE_HOME", "/h");
        match parse_rc_line("alias ll='ls -la'") {
            Some(RcDecl::Alias(n, v)) => {
                assert_eq!(n, "ll");
                assert_eq!(v, "ls -la");
            }
            _ => panic!("expected alias"),
        }
        match parse_rc_line("export PATH=\"$RC_PARSE_HOME/bin:/usr/bin\"") {
            Some(RcDecl::Export(k, v)) => {
                assert_eq!(k, "PATH");
                assert_eq!(v, "/h/bin:/usr/bin");
            }
            _ => panic!("expected export"),
        }
        // Foreign / non-portable lines are ignored, never crash.
        assert!(parse_rc_line("setopt AUTO_CD").is_none());
        assert!(parse_rc_line("myfunc() { echo hi; }").is_none());
        assert!(parse_rc_line("alias -g G='| grep'").is_none());
        assert!(parse_rc_line("# a comment").is_none());
        assert!(parse_rc_line("").is_none());
    }
}
